var e=[{id:`L3_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`무엇을 보고 있니?`,JPN:`何を見ているの？`,ENG:`What are you looking at?`,TWN:`你在看什麼？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`달을 보고 있습니다.`,JPN:`お月様を眺めていました。`,ENG:`I was looking at the moon.`,TWN:`我在看月亮。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`밑에서 볼 땐 작은 경단 같았는데, 여기서 보니 정말 크고 둥글어요.`,JPN:`下から見た時は小さなお団子みたいだったのに、
ここから見ると丸くて大きいですね。`,ENG:`It looked like a little ball of dango from below, but it’s really big and round when you look at it from here.`,TWN:`在底下看的時候，像個小糯米糰，在這裡一看，真的是又大又圓呢。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`그래, 예쁘구나.`,JPN:`そうね、とても綺麗だわ。`,ENG:`Yes, it is pretty.`,TWN:`是啊，很漂亮。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`여기서는 참 많은 것들이 또렷하게 보이는 것 같아.`,JPN:`ここから眺めると、いろんなものがはっきり見えるわね。`,ENG:`Everything is so crystal clear when you look at them from here.`,TWN:`在這裡能看清楚很多東西。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`바람이 찬데, 녹차 마실래?`,JPN:`風が冷たいわね。温かいお茶でも飲む？`,ENG:`The wind is cold. Do you want some green tea?`,TWN:`風有點涼，要來杯綠茶嗎？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`네, 감사합니다.`,JPN:`はい、ありがとうございます。`,ENG:`Yes, thank you.`,TWN:`好，謝謝。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`우읏……. 써.`,JPN:`ううっ……苦い。`,ENG:`Urgh... It’s bitter.`,TWN:`唔……好苦。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`후훗. 입맛에 잘 안 맞나 보구나. 물을 더 넣어 줄게.`,JPN:`ふふっ、あなたには濃すぎたかしら？　お湯を足してあげるわ。`,ENG:`Hah hah, here, let me add some more water.`,TWN:`呵呵，看來不合你胃口，我再給你加點水吧。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`괜찮습니다. 인생을 살아가려면 쓴 맛도 즐길 줄 알아야 하는 법이니까요.`,JPN:`大丈夫です。
人生を生きていくには苦味も楽しまなければならないですから。`,ENG:`It’s okay. Life is bitter, and I should learn how to enjoy the bitterness.`,TWN:`沒關係，人生在世也要懂得享受苦味。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`어머, 그런 말은 어디서 배웠니?`,JPN:`あら、そんな言葉どこで覚えてきたの？`,ENG:`Oh, where did you hear that?`,TWN:`哎唷，這些話是從哪裡學的？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`나나하라 당주님께서 가르쳐 주셨습니다.`,JPN:`七原家のご当主様が教えてくださいました。`,ENG:`From Lady Nanahara.`,TWN:`是七原堂主教我的。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`그 분은 또 애한테 이상한 걸 가르치셨네…….`,JPN:`あのお方ったら、子どもに変なことを教えちゃって……`,ENG:`That’s a strange thing to say to a child.`,TWN:`堂主又教孩子一些奇怪的東西……`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`그래도 기억해 두면 언젠가 도움이 되겠지. 실없는 소릴 하는 분은 아니니까.`,JPN:`まあでも、覚えておけばいつか役に立つかもしれないわね。
くだらないことを口にするようなお方じゃないから。`,ENG:`But everything she does is for a reason, so I suppose she meant you good.`,TWN:`我只是說說而已，堂主教你的你要記得，她不是會胡亂說話的人，總有一天會派上用場的。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`네, 어머니.`,JPN:`はい、母上。`,ENG:`Yes, mother.`,TWN:`好的，媽媽。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:null,text:{KOREA:`부전대장님, 이만 가실 시간입니다.`,JPN:`副戦隊長、そろそろお時間でございます。`,ENG:`Deputy Commander, it’s time to go.`,TWN:`副戰隊長，該出發了。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_QM`,text:{KOREA:`네~ 금방 가요~`,JPN:`はーい、すぐに行きまーす。`,ENG:`Yes, I’ll be right there.`,TWN:`好~ 馬上來~`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:{char_id:`KANADE_JAPAN_NULL_QM`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};